#!/usr/bin/env python3
import argparse
from pathlib import Path

TEMPLATE = """
// AUTO-GENERATED by gen_overload.py

target C {{
  files: ["{lib_path}"]
}}

preamble {{=
#include <stdlib.h>
#include "ms_eval_log.h"
#include "core/reactor.h"

static int ms_eval_steps = {steps};
static int ms_eval_seed = {seed};
static int ms_eval_hc_deadline_us = {hc_deadline_us};
static int ms_eval_lc_deadline_us = {lc_deadline_us};
static int ms_eval_hc_work_us = {hc_work_us};
static int ms_eval_lc_work_us = {lc_work_us};
static double ms_eval_load_factor = {load_factor};

static double ms_eval_get_env_double(const char* key, double fallback) {{
  const char* v = getenv(key);
  return v ? atof(v) : fallback;
}}
=}}

main reactor Overload {{
  timer t(0, {period_us} us);
  state int step = 0;

  reaction(startup) {{=
    ms_eval_load_factor = ms_eval_get_env_double("MS_EVAL_LOAD_FACTOR", ms_eval_load_factor);
    const char* log_path = getenv("LF_APP_LOG");
    const char* mode = getenv("MS_MODE");
    ms_eval_log_init(log_path, "e3", mode, {total_reactions}, ms_eval_steps,
                     ms_eval_hc_work_us, ms_eval_hc_deadline_us, ms_eval_load_factor, ms_eval_seed);
  =}}

{reactions_block}
}}
"""

REACTION_TEMPLATE = """
  reaction(t) {{=
    const int reaction_id = {rid};
    int64_t logical = (int64_t)lf_time_logical();
    int64_t physical = (int64_t)lf_time_physical();
    ms_eval_log_reaction_start(reaction_id, logical, physical);
    ms_eval_busy_wait_us({work_us_expr});
    int64_t physical_end = (int64_t)lf_time_physical();
    int missed = ({deadline_us} > 0 &&
                  physical_end > logical + (int64_t){deadline_us} * 1000LL);
    ms_eval_log_reaction_end(reaction_id, logical, physical_end, {deadline_us}, missed);
    {step_logic}
  =}}
"""


def main() -> None:
    ap = argparse.ArgumentParser()
    ap.add_argument("--out", required=True)
    ap.add_argument("--hc", type=int, required=True)
    ap.add_argument("--lc", type=int, required=True)
    ap.add_argument("--hc-work-us", type=int, required=True)
    ap.add_argument("--lc-work-us", type=int, required=True)
    ap.add_argument("--hc-deadline-us", type=int, required=True)
    ap.add_argument("--lc-deadline-us", type=int, required=True)
    ap.add_argument("--period-us", type=int, default=1000)
    ap.add_argument("--steps", type=int, default=1000)
    ap.add_argument("--seed", type=int, default=1)
    ap.add_argument("--load-factor", type=float, default=1.0)
    ap.add_argument("--lib-path", default="../lf-templates/lib/ms_eval_log.c")
    args = ap.parse_args()

    reactions = []
    total = args.hc + args.lc
    for rid in range(total):
        is_hc = rid < args.hc
        if is_hc:
            work_expr = "ms_eval_hc_work_us"
            deadline = "ms_eval_hc_deadline_us"
        else:
            work_expr = "(int)(ms_eval_lc_work_us * ms_eval_load_factor)"
            deadline = "ms_eval_lc_deadline_us"
        step_logic = ""
        if rid == 0:
            step_logic = "step++; if (step >= ms_eval_steps) lf_request_stop();"
        reactions.append(
            REACTION_TEMPLATE.format(
                rid=rid,
                work_us_expr=work_expr,
                deadline_us=deadline,
                step_logic=step_logic,
            )
        )

    out_path = Path(args.out)
    out_path.parent.mkdir(parents=True, exist_ok=True)
    out_path.write_text(
        TEMPLATE.format(
            lib_path=args.lib_path,
            steps=args.steps,
            seed=args.seed,
            hc_deadline_us=args.hc_deadline_us,
            lc_deadline_us=args.lc_deadline_us,
            hc_work_us=args.hc_work_us,
            lc_work_us=args.lc_work_us,
            load_factor=args.load_factor,
            total_reactions=total,
            period_us=args.period_us,
            reactions_block="\n".join(reactions),
        )
    )


if __name__ == "__main__":
    main()
